    31  /**
    32   * A custom classloader dedicated to loading Connect plugin classes in classloading isolation.
    33   * <p>
    34   * Under the current scheme for classloading isolation in Connect, a plugin classloader loads the
    35   * classes that it finds in its urls. For classes that are either not found or are not supposed to
    36   * be loaded in isolation, this plugin classloader delegates their loading to its parent. This makes
    37   * this classloader a child-first classloader.
    38   * <p>
    39   * This class is thread-safe and parallel capable.
    40   */
    41  public class PluginClassLoader extends URLClassLoader {
    42      private static final Logger log = LoggerFactory.getLogger(PluginClassLoader.class);
    43      private final URL pluginLocation;
    44
    45      static {
    46          ClassLoader.registerAsParallelCapable();
    47      }
    48
    49      /**
    50       * Constructor that accepts a specific classloader as parent.
    51       *
    52       * @param pluginLocation the top-level location of the plugin to be loaded in isolation by this
    53       * classloader.
    54       * @param urls the list of urls from which to load classes and resources for this plugin.
    55       * @param parent the parent classloader to be used for delegation for classes that were
    56       * not found or should not be loaded in isolation by this classloader.
    57       */
    58      public PluginClassLoader(URL pluginLocation, URL[] urls, ClassLoader parent) {
    59          super(urls, parent);
    60          this.pluginLocation = Objects.requireNonNull(pluginLocation, "Plugin location must be non-null");
    61      }
    62
    63      /**
    64       * Returns the top-level location of the classes and dependencies required by the plugin that
    65       * is loaded by this classloader.
    66       *
    67       * @return the plugin location.
    68       */
    69      public String location() {
    70          return pluginLocation.toString();
    71      }
    72
    73      @Override
    74      public String toString() {
    75          return "PluginClassLoader{pluginLocation=" + pluginLocation + "}";
    76      }
    77
    78      @Override
    79      public URL getResource(String name) {
    80          Objects.requireNonNull(name);
    81
    82          URL url = findResource(name);
    83          if (url == null) {
    84              url = super.getResource(name);
    85          }
    86          return url;
    87      }
    88
    89      @Override
    90      public Enumeration<URL> getResources(String name) throws IOException {
    91          Objects.requireNonNull(name);
    92          List<URL> resources = new ArrayList<>();
    93          for (Enumeration<URL> foundLocally = findResources(name); foundLocally.hasMoreElements();) {
    94              URL url = foundLocally.nextElement();
    95              if (url != null)
    96                  resources.add(url);
    97          }
    98          // Explicitly call the parent implementation instead of super to avoid double-listing the local resources
    99          for (Enumeration<URL> foundByParent = getParent().getResources(name); foundByParent.hasMoreElements();) {
   100              URL url = foundByParent.nextElement();
   101              if (url != null)
   102                  resources.add(url);
   103          }
   104          return Collections.enumeration(resources);
   105      }
   106
   107      // This method needs to be thread-safe because it is supposed to be called by multiple
   108      // Connect tasks. While findClass is thread-safe, defineClass called within loadClass of the
   109      // base method is not. More on multithreaded classloaders in:
   110      // https://docs.oracle.com/javase/7/docs/technotes/guides/lang/cl-mt.html
   111      @Override
   112      protected Class<?> loadClass(String name, boolean resolve) throws ClassNotFoundException {
   113          synchronized (getClassLoadingLock(name)) {
   114              Class<?> klass = findLoadedClass(name);
   115              if (klass == null) {
   116                  try {
   117                      if (PluginUtils.shouldLoadInIsolation(name)) {
   118                          klass = findClass(name);
   119                      }
   120                  } catch (ClassNotFoundException e) {
   121                      // Not found in loader's path. Search in parents.
   122                      log.trace("Class '{}' not found. Delegating to parent", name);
   123                  }
   124              }
   125              if (klass == null) {
   126                  klass = super.loadClass(name, false);
   127              }
   128              if (resolve) {
   129                  resolveClass(klass);
   130              }
   131              return klass;
   132          }
   133      }
   134  }

