    39  /**
    40   * Superclass for plugin discovery implementations.
    41   *
    42   * <p>Callers of this class should use {@link #discoverPlugins(Set)} to discover plugins which are present in the
    43   * passed-in {@link PluginSource} instances.
    44   *
    45   * <p>Implementors of this class should implement {@link #scanPlugins(PluginSource)}, in order to scan a single source.
    46   * The returned {@link PluginScanResult} should contain only plugins which are loadable from the passed-in source.
    47   * The superclass has some common functionality which is usable in subclasses, and handles merging multiple results.
    48   *
    49   * <p>Implementations of this class must be thread-safe, but may have side effects on the provided {@link ClassLoader}
    50   * instances and plugin classes which may not be thread safe. This depends on the thread safety of the plugin
    51   * implementations, due to the necessity of initializing and instantiate plugin classes to evaluate their versions.
    52   */
    53  public abstract class PluginScanner {
    54
    55      private static final Logger log = LoggerFactory.getLogger(PluginScanner.class);
    56
    57      /**
    58       * Entry point for plugin scanning. Discovers plugins present in any of the provided plugin sources.
    59       * <p>See the implementation-specific documentation for the conditions for a plugin to appear in this result.
    60       * @param sources to scan for contained plugins
    61       * @return A {@link PluginScanResult} containing all plugins which this scanning implementation could discover.
    62       */
    63      public PluginScanResult discoverPlugins(Set<PluginSource> sources) {
    64          long startMs = System.currentTimeMillis();
    65          List<PluginScanResult> results = new ArrayList<>();
    66          for (PluginSource source : sources) {
    67              results.add(scanUrlsAndAddPlugins(source));
    68          }
    69          long endMs = System.currentTimeMillis();
    70          log.info("Scanning plugins with {} took {} ms", getClass().getSimpleName(), endMs - startMs);
    71          return new PluginScanResult(results);
    72      }
    73
    74      private PluginScanResult scanUrlsAndAddPlugins(PluginSource source) {
    75          log.info("Loading plugin from: {}", source);
    76          if (log.isDebugEnabled()) {
    77              log.debug("Loading plugin urls: {}", Arrays.toString(source.urls()));
    78          }
    79          PluginScanResult plugins = scanPlugins(source);
    80          log.info("Registered loader: {}", source.loader());
    81          loadJdbcDrivers(source.loader());
    82          return plugins;
    83      }
    84
    85      /**
    86       * Implementation-specific strategy for scanning a single {@link PluginSource}.
    87       * @param source A single source to scan for plugins.
    88       * @return A {@link PluginScanResult} containing all plugins which this scanning implementation could discover.
    89       */
    90      protected abstract PluginScanResult scanPlugins(PluginSource source);
    91
    92      private void loadJdbcDrivers(final ClassLoader loader) {
    93          // Apply here what java.sql.DriverManager does to discover and register classes
    94          // implementing the java.sql.Driver interface.
    95          SecurityManagerCompatibility.get().doPrivileged(
    96              () -> {
    97                  ServiceLoader<Driver> loadedDrivers = ServiceLoader.load(
    98                          Driver.class,
    99                          loader
   100                  );
   101                  Iterator<Driver> driversIterator = loadedDrivers.iterator();
   102                  try {
   103                      while (driversIterator.hasNext()) {
   104                          Driver driver = driversIterator.next();
   105                          log.debug(
   106                                  "Registered java.sql.Driver: {} to java.sql.DriverManager",
   107                                  driver
   108                          );
   109                      }
   110                  } catch (Throwable t) {
   111                      log.debug(
   112                              "Ignoring java.sql.Driver classes listed in resources but not"
   113                                      + " present in class loader's classpath: ",
   114                              t
   115                      );
   116                  }
   117                  return null;
   118              }
   119          );
   120      }
   121
   122      @SuppressWarnings({"rawtypes", "unchecked"})
   123      protected <T> PluginDesc<T> pluginDesc(Class<? extends T> plugin, String version, PluginType type, PluginSource source) {
   124          return new PluginDesc(plugin, version, type, source.loader());
   125      }
   126
   127      @SuppressWarnings("unchecked")
   128      protected <T> SortedSet<PluginDesc<T>> getServiceLoaderPluginDesc(PluginType type, PluginSource source) {
   129          SortedSet<PluginDesc<T>> result = new TreeSet<>();
   130          ServiceLoader<T> serviceLoader = ServiceLoader.load((Class<T>) type.superClass(), source.loader());
   131          Iterator<T> iterator = serviceLoader.iterator();
   132          while (handleLinkageError(type, source, iterator::hasNext)) {
   133              try (LoaderSwap loaderSwap = withClassLoader(source.loader())) {
   134                  T pluginImpl;
   135                  try {
   136                      pluginImpl = handleLinkageError(type, source, iterator::next);
   137                  } catch (ServiceConfigurationError t) {
   138                      log.error("Failed to discover {} in {}{}",
   139                              type.simpleName(), source, reflectiveErrorDescription(t.getCause()), t);
   140                      continue;
   141                  }
   142                  Class<? extends T> pluginKlass = (Class<? extends T>) pluginImpl.getClass();
   143                  if (pluginKlass.getClassLoader() != source.loader()) {
   144                      log.debug("{} from other classloader {} is visible from {}, excluding to prevent isolated loading",
   145                              type.simpleName(), pluginKlass.getClassLoader(), source);
   146                      continue;
   147                  }
   148                  result.add(pluginDesc(pluginKlass, versionFor(pluginImpl), type, source));
   149              }
   150          }
   151          return result;
   152      }
   153
   154      /**
   155       * Helper to evaluate a {@link ServiceLoader} operation while handling {@link LinkageError}s.
   156       *
   157       * @param type The plugin type which is being loaded
   158       * @param function A function on a {@link ServiceLoader}'s {@link Iterator} which may throw {@link LinkageError}
   159       * @return the return value of function
   160       * @throws Error errors thrown by the passed-in function
   161       * @param <U> Return value of the passed-in function
   162       */
   163      private <U> U handleLinkageError(PluginType type, PluginSource source, Supplier<U> function) {
   164          // It's difficult to know for sure if the iterator was able to advance past the first broken
   165          // plugin class, or if it will continue to fail on that broken class for any subsequent calls
   166          // to Iterator::hasNext or Iterator::next
   167          // For reference, see https://bugs.openjdk.org/browse/JDK-8196182, which describes
   168          // the behavior we are trying to mitigate with this logic as buggy, but indicates that a fix
   169          // in the JDK standard library ServiceLoader implementation is unlikely to land
   170          LinkageError lastError = null;
   171          // Try a fixed maximum number of times in case the ServiceLoader cannot move past a faulty plugin,
   172          // but the LinkageError varies between calls. This limit is chosen to be higher than the typical number
   173          // of plugins in a single plugin location, and to limit the amount of log-spam on startup.
   174          for (int i = 0; i < 100; i++) {
   175              try {
   176                  return function.get();
   177              } catch (LinkageError t) {
   178                  // As an optimization, hide subsequent error logs if two consecutive errors look similar.
   179                  // This reduces log-spam for iterators which cannot advance and rethrow the same exception.
   180                  if (lastError == null
   181                          || !Objects.equals(lastError.getClass(), t.getClass())
   182                          || !Objects.equals(lastError.getMessage(), t.getMessage())) {
   183                      log.error("Failed to discover {} in {}{}",
   184                              type.simpleName(), source, reflectiveErrorDescription(t.getCause()), t);
   185                  }
   186                  lastError = t;
   187              }
   188          }
   189          log.error("Received excessive ServiceLoader errors: assuming the runtime ServiceLoader implementation cannot " +
   190                          "skip faulty implementations. Use a different JRE, or resolve LinkageErrors for plugins in {}",
   191                  source, lastError);
   192          throw lastError;
   193      }
   194
   195      protected static <T> String versionFor(T pluginImpl) {
   196          try {
   197              if (pluginImpl instanceof Versioned) {
   198                  return ((Versioned) pluginImpl).version();
   199              }
   200          } catch (Throwable t) {
   201              log.error("Failed to get plugin version for {}", pluginImpl.getClass(), t);
   202          }
   203          return PluginDesc.UNDEFINED_VERSION;
   204      }
   205
   206      protected static String reflectiveErrorDescription(Throwable t) {
   207          if (t instanceof NoSuchMethodException) {
   208              return ": Plugin class must have a no-args constructor, and cannot be a non-static inner class";
   209          } else if (t instanceof SecurityException) {
   210              return ": Security settings must allow reflective instantiation of plugin classes";
   211          } else if (t instanceof IllegalAccessException) {
   212              return ": Plugin class default constructor must be public";
   213          } else if (t instanceof ExceptionInInitializerError) {
   214              return ": Failed to statically initialize plugin class";
   215          } else if (t instanceof InvocationTargetException) {
   216              return ": Failed to invoke plugin constructor";
   217          } else if (t instanceof LinkageError) {
   218              return ": Plugin class has a dependency which is missing or invalid";
   219          } else {
   220              return "";
   221          }
   222      }
   223
   224      protected LoaderSwap withClassLoader(ClassLoader loader) {
   225          ClassLoader savedLoader = Plugins.compareAndSwapLoaders(loader);
   226          try {
   227              return new LoaderSwap(savedLoader);
   228          } catch (Throwable t) {
   229              Plugins.compareAndSwapLoaders(savedLoader);
   230              throw t;
   231          }
   232      }
   233  }

