    39  import io.github.classgraph.ClassGraph;
    40  import io.github.classgraph.ClassInfoList;
    41  import io.github.classgraph.ScanResult;
    42
    43  /**
    44   * A {@link PluginScanner} implementation which uses reflection and {@link ServiceLoader} to discover plugins.
    45   * <p>This implements the legacy discovery strategy, which uses a combination of reflection and service loading in
    46   * order to discover plugins. Specifically, a plugin appears in the scan result if all the following conditions are true:
    47   * <ul>
    48   *     <li>The class and direct dependencies can be loaded</li>
    49   *     <li>The class is concrete</li>
    50   *     <li>The class is public</li>
    51   *     <li>The class has a no-args constructor</li>
    52   *     <li>The no-args constructor is public</li>
    53   *     <li>Static initialization of the class completes without throwing an exception</li>
    54   *     <li>The no-args constructor completes without throwing an exception</li>
    55   *     <li>One of the following is true:
    56   *         <ul>
    57   *             <li>Is a subclass of {@link SinkConnector}, {@link SourceConnector}, {@link Converter},
    58   *             {@link HeaderConverter}, {@link Transformation}, or {@link Predicate}</li>
    59   *             <li>Is a subclass of {@link ConfigProvider}, {@link ConnectRestExtension}, or
    60   *             {@link ConnectorClientConfigOverridePolicy}, and has a {@link ServiceLoader} compatible
    61   *             manifest file or module declaration</li>
    62   *         </ul>
    63   *     </li>
    64   * </ul>
    65   * <p>Note: This scanner has a runtime proportional to the number of overall classes in the passed-in
    66   * {@link PluginSource} objects, which may be significant for plugins with large dependencies. For a more performant
    67   * implementation, consider using {@link ServiceLoaderScanner} and follow migration instructions for
    68   * <a href="https://cwiki.apache.org/confluence/display/KAFKA/KIP-898%3A+Modernize+Connect+plugin+discovery">KIP-898</a>.
    69   */
    70  public class ReflectionScanner extends PluginScanner {
    71
    72      private static final Logger log = LoggerFactory.getLogger(ReflectionScanner.class);
    73
    74      private static <T> String versionFor(Class<? extends T> pluginKlass) throws ReflectiveOperationException {
    75          T pluginImpl = pluginKlass.getDeclaredConstructor().newInstance();
    76          return versionFor(pluginImpl);
    77      }
    78
    79      @Override
    80      protected PluginScanResult scanPlugins(PluginSource source) {
    81          ClassGraph classGraphBuilder = new ClassGraph()
    82                  .overrideClassLoaders(classLoaderOrder(source))
    83                  .enableExternalClasses()
    84                  .enableClassInfo();
    85          try (ScanResult classGraph = classGraphBuilder.scan()) {
    86              return new PluginScanResult(
    87                    getPluginDesc(classGraph, PluginType.SINK, source),
    88                    getPluginDesc(classGraph, PluginType.SOURCE, source),
    89                    getPluginDesc(classGraph, PluginType.CONVERTER, source),
    90                    getPluginDesc(classGraph, PluginType.HEADER_CONVERTER, source),
    91                    getTransformationPluginDesc(source, classGraph),
    92                    getPredicatePluginDesc(source, classGraph),
    93                    getServiceLoaderPluginDesc(PluginType.CONFIGPROVIDER, source),
    94                    getServiceLoaderPluginDesc(PluginType.REST_EXTENSION, source),
    95                    getServiceLoaderPluginDesc(PluginType.CONNECTOR_CLIENT_CONFIG_OVERRIDE_POLICY, source)
    96            );
    97          }
    98      }
    99
   100      @SuppressWarnings({"unchecked"})
   101      private SortedSet<PluginDesc<Predicate<?>>> getPredicatePluginDesc(PluginSource source, ScanResult classGraph) {
   102          return (SortedSet<PluginDesc<Predicate<?>>>) (SortedSet<?>) getPluginDesc(classGraph, PluginType.PREDICATE, source);
   103      }
   104
   105      @SuppressWarnings({"unchecked"})
   106      private SortedSet<PluginDesc<Transformation<?>>> getTransformationPluginDesc(PluginSource source, ScanResult classGraph) {
   107          return (SortedSet<PluginDesc<Transformation<?>>>) (SortedSet<?>) getPluginDesc(classGraph, PluginType.TRANSFORMATION, source);
   108      }
   109
   110      private ClassLoader[] classLoaderOrder(PluginSource source) {
   111          // Classgraph will first scan all the class URLs from the provided classloader chain and use said chain during classloading.
   112          // We compute and provide the classloader chain starting from the isolated PluginClassLoader to ensure that it adheres
   113          // to the child first delegation model used in connect. In addition, classgraph can fail to find URLs from the
   114          // application classloader as it uses an illegal reflections access. Providing the entire chain of classloaders
   115          // which included the application classloader forces classpath URLs to be scanned separately.
   116          List<ClassLoader> classLoaderOrder = new ArrayList<>();
   117          ClassLoader cl = source.loader();
   118          while (cl != null) {
   119              classLoaderOrder.add(cl);
   120              cl = cl.getParent();
   121          }
   122          return classLoaderOrder.toArray(new ClassLoader[0]);
   123      }
   124
   125      @SuppressWarnings({"unchecked"})
   126      private <T> SortedSet<PluginDesc<T>> getPluginDesc(
   127              ScanResult classGraph,
   128              PluginType type,
   129              PluginSource source
   130      ) {
   131          ClassInfoList plugins;
   132          Class<T> klass = (Class<T>) type.superClass();
   133          try {
   134              if (klass.isInterface()) {
   135                  plugins = classGraph.getClassesImplementing(klass.getName());
   136              } else {
   137                  plugins = classGraph.getSubclasses(klass.getName());
   138              }
   139          } catch (Exception e) {
   140              log.debug("Reflections scanner could not find any {} in {} for URLs: {}",
   141                      type, source, source.urls(), e);
   142              return Collections.emptySortedSet();
   143          }
   144
   145          SortedSet<PluginDesc<T>> result = new TreeSet<>();
   146          for (Class<? extends T> pluginKlass : plugins.getStandardClasses().loadClasses(klass, true)) {
   147              if (!PluginUtils.isConcrete(pluginKlass)) {
   148                  log.debug("Skipping {} in {} as it is not concrete implementation", pluginKlass, source);
   149                  continue;
   150              }
   151              if (pluginKlass.getClassLoader() != source.loader()) {
   152                  log.debug("{} from other classloader {} is visible from {}, excluding to prevent isolated loading",
   153                          pluginKlass, pluginKlass.getClassLoader(), source);
   154                  continue;
   155              }
   156              try (LoaderSwap loaderSwap = withClassLoader(source.loader())) {
   157                  result.add(pluginDesc(pluginKlass, versionFor(pluginKlass), type, source));
   158              } catch (ReflectiveOperationException | LinkageError e) {
   159                  log.error("Failed to discover {} in {}: Unable to instantiate {}{}",
   160                          type.simpleName(), source, pluginKlass.getSimpleName(),
   161                          reflectiveErrorDescription(e), e);
   162              }
   163          }
   164          return result;
   165      }
   166  }

