    58          return new PluginScanResult(
    59                  getServiceLoaderPluginDesc(PluginType.SINK, source),
    60                  getServiceLoaderPluginDesc(PluginType.SOURCE, source),
    61                  getServiceLoaderPluginDesc(PluginType.CONVERTER, source),
    62                  getServiceLoaderPluginDesc(PluginType.HEADER_CONVERTER, source),
    63                  getTransformationPluginDesc(source),
    64                  getPredicatePluginDesc(source),
    65                  getServiceLoaderPluginDesc(PluginType.CONFIGPROVIDER, source),
    66                  getServiceLoaderPluginDesc(PluginType.REST_EXTENSION, source),
    67                  getServiceLoaderPluginDesc(PluginType.CONNECTOR_CLIENT_CONFIG_OVERRIDE_POLICY, source)
    68          );
    69      }
