   101      @Override
   102      public boolean equals(Object o) {
   103          if (this == o) {
   104              return true;
   105          }
   106          if (!(o instanceof PluginDesc<?> that)) {
   107              return false;
   108          }
   109          return Objects.equals(klass, that.klass) &&
   110                  Objects.equals(version, that.version) &&
