   119      @Override
   120      public int compareTo(PluginDesc<?> other) {
   121          int nameComp = name.compareTo(other.name);
   122          int versionComp = encodedVersion.compareTo(other.encodedVersion);
   123          // isolated plugins appear after classpath plugins when they have identical versions.
   124          int isolatedComp = Boolean.compare(other.loader instanceof PluginClassLoader, loader instanceof PluginClassLoader);
   125          // choose an arbitrary order between different locations and types
   126          int loaderComp = location.compareTo(other.location);
   127          int typeComp = type.compareTo(other.type);
   128          return nameComp != 0 ? nameComp :
   129                  versionComp != 0 ? versionComp :
   130                          isolatedComp != 0 ? isolatedComp :
   131                                  loaderComp != 0 ? loaderComp :
   132                                          typeComp;
