   485      /**
   486       * Load an internal converter, used by the worker for (de)serializing data in internal topics.
   487       *
   488       * @param isKey           whether the converter is a key converter
   489       * @param className       the class name of the converter
   490       * @param converterConfig the properties to configure the converter with
   491       * @return the instantiated and configured {@link Converter}; never null
   492       * @throws ConnectException if the {@link Converter} implementation class could not be found
   493       */
   494      public Converter newInternalConverter(boolean isKey, String className, Map<String, String> converterConfig) {
   495          Class<? extends Converter> klass;
   496          try {
   497              klass = pluginClass(delegatingLoader, className, Converter.class);
   498          } catch (ClassNotFoundException e) {
   499              throw new ConnectException("Failed to load internal converter class " + className);
   500          }
   501
   502          Converter plugin;
   503          try (LoaderSwap loaderSwap = withClassLoader(klass.getClassLoader())) {
   504              plugin = newPlugin(klass);
   505              plugin.configure(converterConfig, isKey);
   506          }
   507          return plugin;
   508      }
