   514       * @param config             the configuration containing the {@link HeaderConverter}'s configuration; may not be null
   515       * @param classPropertyName  the name of the property that contains the name of the {@link HeaderConverter} class; may not be null
   516       * @param classLoaderUsage   the name of the property that contains the version of the {@link HeaderConverter} class; may not be null
   517       * @return the instantiated and configured {@link HeaderConverter}; null if the configuration did not define the specified property
   518       * @throws ConnectException if the {@link HeaderConverter} implementation class could not be found
   519       */
   520      public HeaderConverter newHeaderConverter(AbstractConfig config, String classPropertyName, ClassLoaderUsage classLoaderUsage) {
