   527       *
   528       * @param config                the configuration containing the {@link HeaderConverter}'s configuration; may not be null
   529       * @param classPropertyName     the name of the property that contains the name of the {@link HeaderConverter} class; may not be null
   530       * @param versionPropertyName   the config for the version for the header converter
   531       * @return the instantiated and configured {@link HeaderConverter}; null if the configuration did not define the specified property
   532       * @throws ConnectException if the {@link HeaderConverter} implementation class could not be found
   533       */
   534      public HeaderConverter newHeaderConverter(AbstractConfig config, String classPropertyName, String versionPropertyName) {
   535          ClassLoaderUsage classLoader = config.getString(versionPropertyName) == null ? ClassLoaderUsage.CURRENT_CLASSLOADER : ClassLoaderUsage.PLUGINS;
