   637      /**
   638       * If the given class names are available in the classloader, return a list of new configured
   639       * instances. If the instances implement {@link Configurable}, they are configured with provided {@param config}
   640       *
   641       * @param klassNames         the list of class names of plugins that needs to instantiated and configured
   642       * @param config             the configuration containing the {@link org.apache.kafka.connect.runtime.Worker}'s configuration; may not be {@code null}
   643       * @param pluginKlass        the type of the plugin class that is being instantiated
   644       * @return the instantiated and configured list of plugins of type <T>; empty list if the {@param klassNames} is {@code null} or empty
   645       * @throws ConnectException if the implementation class could not be found
   646       */
   647      public <T> List<T> newPlugins(List<String> klassNames, AbstractConfig config, Class<T> pluginKlass) {
   648          List<T> plugins = new ArrayList<>();
   649          if (klassNames != null) {
   650              for (String klassName : klassNames) {
   651                  plugins.add(newPlugin(klassName, config, pluginKlass));
   652              }
   653          }
   654          return plugins;
   655      }
