   657      public <T> T newPlugin(String klassName, AbstractConfig config, Class<T> pluginKlass) {
   658          T plugin;
   659          Class<? extends T> klass;
   660          try {
   661              klass = pluginClass(delegatingLoader, klassName, pluginKlass);
   662          } catch (ClassNotFoundException e) {
   663              String msg = String.format("Failed to find any class that implements %s and which "
   664                                         + "name matches %s", pluginKlass, klassName);
   665              throw new ConnectException(msg);
   666          }
   667          try (LoaderSwap loaderSwap = withClassLoader(klass.getClassLoader())) {
   668              plugin = newPlugin(klass);
   669              if (plugin instanceof Versioned versionedPlugin) {
   670                  if (Utils.isBlank(versionedPlugin.version())) {
   671                      throw new ConnectException("Version not defined for '" + klassName + "'");
   672                  }
   673              }
   674              if (plugin instanceof Configurable) {
   675                  ((Configurable) plugin).configure(config.originals());
   676              }
   677          }
   678          return plugin;
   679      }
