    27          if (value == null) {
    28              // The value will be null if the class couldn't be found; no point in performing follow-up validation
    29              return;
    30          }
    31
    32          Class<?> cls = (Class<?>) value;
    33          try {
    34              Object o = cls.getDeclaredConstructor().newInstance();
    35              Utils.maybeCloseQuietly(o, o + " (instantiated for preflight validation");
    36          } catch (NoSuchMethodException | IllegalAccessException e) {
    37              throw new ConfigException(name, cls.getName(), "Could not find a public no-argument constructor for class" + (e.getMessage() != null ? ": " + e.getMessage() : ""));
    38          } catch (ReflectiveOperationException | LinkageError | RuntimeException e) {
    39              throw new ConfigException(name, cls.getName(), "Could not instantiate class" + (e.getMessage() != null ? ": " + e.getMessage() : ""));
    40          }
    41      }
    42
    43      @Override
    44      public String toString() {
    45          return "A class with a public, no-argument constructor";
