    26
    27  import java.util.Map;
    28  import java.util.concurrent.ConcurrentHashMap;
    29
    30  public class CachedConnectors {
    31
    32      private static final String LATEST_VERSION = "latest";
    33
    34      private final Map<String, Map<String, Connector>> connectors;
    35      private final Map<String, Throwable> invalidConnectors;
    36      private final Map<String, Map<String, VersionedPluginLoadingException>> invalidVersions;
    37      private final Plugins plugins;
    38
    39      public CachedConnectors(Plugins plugins) {
    40          this.plugins = plugins;
    41          this.connectors = new ConcurrentHashMap<>();
    42          this.invalidConnectors = new ConcurrentHashMap<>();
    43          this.invalidVersions = new ConcurrentHashMap<>();
    44      }
    45
    46      private void validate(String connectorName, VersionRange range) throws ConnectException, VersionedPluginLoadingException {
    47          if (invalidConnectors.containsKey(connectorName)) {
    48              throw new ConnectException(invalidConnectors.get(connectorName));
    49          }
    50
    51          String version = range == null ? LATEST_VERSION : range.toString();
    52          if (invalidVersions.containsKey(connectorName) && invalidVersions.get(connectorName).containsKey(version)) {
    53              throw new VersionedPluginLoadingException(invalidVersions.get(connectorName).get(version).getMessage());
    54          }
    55      }
    56
    57      private Connector lookup(String connectorName, VersionRange range) {
    58          String version = range == null ? LATEST_VERSION : range.toString();
    59          if (connectors.containsKey(connectorName) && connectors.get(connectorName).containsKey(version)) {
    60              return connectors.get(connectorName).get(version);
    61          }
    62
    63          try {
    64              Connector connector = plugins.newConnector(connectorName, range);
    65              connectors.computeIfAbsent(connectorName, k -> new ConcurrentHashMap<>()).put(version, connector);
    66              return connector;
    67          } catch (VersionedPluginLoadingException e) {
    68              invalidVersions.computeIfAbsent(connectorName, k -> new ConcurrentHashMap<>()).put(version, e);
    69              throw e;
    70          } catch (Exception e) {
    71              invalidConnectors.put(connectorName, e);
    72              throw e;
    73          }
    74      }
    75
    76      public Connector getConnector(String connectorName, VersionRange range) {
    77          validate(connectorName, range);
    78          return lookup(connectorName, range);
    79      }
    80  }

